#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
int main(void) {
    const char *path = "/tmp/kf_fd_open_test.txt";
    int fd = open(path, O_CREAT | O_WRONLY | O_TRUNC, 0644);
    const char *msg = "hello fd";
    write(fd, msg, strlen(msg));
    close(fd);
    fd = open(path, O_RDONLY);
    char buf[32];
    ssize_t n = read(fd, buf, sizeof(buf) - 1);
    buf[n] = '\0';
    printf("Read: %s\n", buf);
    close(fd);
    unlink(path);
    return 0;
}

