#include <unistd.h>
#include <string.h>

/* == EXEMPLE: écrire et lire un entier via fd ============ */
void example_int_fd(void) {
    int fd = open("/tmp/kf_example.dat", O_CREAT | O_WRONLY | O_TRUNC, 0644);
    int val = 42;
    write(fd, &val, sizeof(val));
    close(fd);
    fd = open("/tmp/kf_example.dat", O_RDONLY);
    int result = 0;
    read(fd, &result, sizeof(result));
    close(fd);
    printf("Got: %d\n", result);
    unlink("/tmp/kf_example.dat");
}

